import { useEffect, useState } from "react";
import { getUsers, blockUser, deleteEmployee } from "../../api/adminApi";
import DashboardLayout from "../../components/layout/DashboardLayout";
import "./"

export default function UsersPage() {
  const [users, setUsers] = useState([]);

  useEffect(() => {
    loadUsers();
  }, []);

  const loadUsers = async () => {
    const data = await getUsers();
    setUsers(data.content || []);
  };

  const handleBlockToggle = async (user) => {
    await blockUser(user.id, !user.blocked);
    loadUsers();
  };

  const handleDelete = async (user) => {
    if (window.confirm(`Удалить пользователя ${user.fullName}?`)) {
      await deleteEmployee(user.id);
      loadUsers();
    }
  };

  return (
    <DashboardLayout>
      <div className="users-page">
        <h2>Пользователи</h2>
        <div className="table-wrapper">
          <table className="users-table">
            <thead>
              <tr>
                <th>ID</th>
                <th>Email</th>
                <th>Имя</th>
                <th>Роль</th>
                <th>Статус</th>
                <th>Действия</th>
              </tr>
            </thead>
            <tbody>
              {users.map((u) => (
                <tr key={u.id} className={u.blocked ? "blocked" : ""}>
                  <td>{u.id}</td>
                  <td>{u.email}</td>
                  <td>{u.fullName}</td>
                  <td>{u.role}</td>
                  <td>
                    <span className={`status ${u.blocked ? "blocked" : "active"}`}>
                      {u.blocked ? "Заблокирован" : "Активен"}
                    </span>
                  </td>
                  <td className="actions">
                    <button onClick={() => handleBlockToggle(u)}>
                      {u.blocked ? "Разблокировать" : "Заблокировать"}
                    </button>
                    <button onClick={() => handleDelete(u)}>Удалить</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </DashboardLayout>
  );
}
